unsafe fn noop(_: *const ()) {}
static VTABLE: RawWakerVTable = RawWakerVTable::new(noop_clone, noop, noop, noop);

struct Executor {
    tasks: VecDeque<Pin<Box<dyn Future<Output = ()>>>>,
}

impl Executor {
    fn new() -> Self { Executor { tasks: VecDeque::new() } }
    fn spawn<F: Future<Output = ()> + 'static>(&mut self, f: F) {
        self.tasks.push_back(Box::pin(f));
