use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};

enum ThenState<A, B> {
    First(A),
    Second(B),
    Done,
}

struct Then<A: Future, B: Future<Output = A::Output>> {
    state: ThenState<A, B>,
}

impl<A: Future, B: Future<Output = A::Output>> Future for Then<A, B> {
    type Output = A::Output;
    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        // Safety: we never move A or B after pinning
        let this = unsafe { self.get_unchecked_mut() };
        loop {
            match &mut this.state {
                ThenState::First(a) => {
                    let pinned_a = unsafe { Pin::new_unchecked(a) };
                    match pinned_a.poll(cx) {
                        Poll::Ready(_) => {
                            // transition requires we replace state
                            // For demo: just go to Done
                            this.state = ThenState::Done;
                        }
                        Poll::Pending => return Poll::Pending,
                    }
                }
                ThenState::Done => return Poll::Ready(unsafe {
                    // placeholder — real impl would hold the result
                    std::mem::zeroed()
                }),
                ThenState::Second(_) => return Poll::Pending,
            }
        }
    }
}

