use std::pin::Pin;
use std::task::{Context, Poll};

trait MyStream {
    type Item;
    fn poll_next(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>>;
}

struct Counter { n: u32, max: u32 }

impl MyStream for Counter {
    type Item = u32;
    fn poll_next(mut self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<Option<u32>> {
        if self.n < self.max {
            self.n += 1;
            Poll::Ready(Some(self.n))
        } else {
            Poll::Ready(None)
        }
    }
}

fn collect_stream<S: MyStream<Item = u32> + Unpin>(mut s: S) -> Vec<u32> {
    use std::task::{RawWaker, RawWakerVTable, Waker};
    unsafe fn noop_clone(p: *const ()) -> RawWaker { RawWaker::new(p, &VTABLE) }
    unsafe fn noop(_: *const ()) {}
    static VTABLE: RawWakerVTable = RawWakerVTable::new(noop_clone, noop, noop, noop);
    let waker = unsafe { Waker::from_raw(RawWaker::new(std::ptr::null(), &VTABLE)) };
    let mut cx = Context::from_waker(&waker);
    let mut results = Vec::new();
    loop {
        match Pin::new(&mut s).poll_next(&mut cx) {
            Poll::Ready(Some(v)) => results.push(v),
            Poll::Ready(None) => break,
            Poll::Pending => {}
        }
    }
    results
}

