use std::pin::Pin;
use std::marker::PhantomPinned;

struct Pinnable {
    data: String,
    ptr: *const String, // self-referential
    _pin: PhantomPinned,
}

impl Drop for Pinnable {
    fn drop(&mut self) {
        // Drop receives &mut Self, not Pin<&mut Self>.
        // This is intentional: drop always runs when the value is being freed,
        // at which point moving into the destructor body is safe because
        // the value is being destroyed anyway.
